# -*- coding: utf-8 -*-
import base64
import io
from pathlib import Path

import pandas as pd
from PIL import Image

def image_to_base64(img: Image.Image) -> str:
    """Convert a PIL Image to a base64-encoded PNG string."""
    buffer = io.BytesIO()
    img.save(buffer, format="PNG")
    return base64.b64encode(buffer.getvalue()).decode("utf-8")

def find_image_folder() -> Path:
    candidates = [Path.cwd() / "docs" / "examples" / "data" / "ImageTest"]
    candidates.extend(
        parent / "docs" / "examples" / "data" / "ImageTest"
        for parent in Path.cwd().parents
    )

    for candidate in candidates:
        if candidate.is_dir():
            return candidate

    raise FileNotFoundError(
        "Could not find docs/examples/data/ImageTest from the current working directory."
    )

image_folder = find_image_folder()
rows = []
for index, image_path in enumerate(sorted(image_folder.iterdir())):
    if not image_path.is_file():
        continue

    with Image.open(image_path) as img:
        rows.append({
            "image_id": index,
            "image_content": image_to_base64(img),
        })

return pd.DataFrame(rows)
